import{_ as n,o as a,c as o,ae as i}from"./chunks/framework.CRIdhvba.js";const u=JSON.parse('{"title":"存储引擎 · 第 1 章 InnoDB 存储模型概览","description":"","frontmatter":{"title":"存储引擎 · 第 1 章 InnoDB 存储模型概览"},"headers":[],"relativePath":"career/backend/db-dev/storage-engine/index.md","filePath":"career/backend/db-dev/storage-engine/index.md"}'),r={name:"career/backend/db-dev/storage-engine/index.md"};function t(l,e,d,s,c,_){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="存储引擎-·-第-1-章-innodb-存储模型概览" tabindex="-1">存储引擎 · 第 1 章 InnoDB 存储模型概览 <a class="header-anchor" href="#存储引擎-·-第-1-章-innodb-存储模型概览" aria-label="Permalink to &quot;存储引擎 · 第 1 章 InnoDB 存储模型概览&quot;">​</a></h1><p>存储引擎是数据库「如何在磁盘上组织与读写数据」的核心组件。以 MySQL 的 InnoDB 为例，它通过页（Page）、段（Segment）、表空间（Tablespace）等概念组织数据。</p><h2 id="_1-1-为什么要了解存储引擎" tabindex="-1">1.1 为什么要了解存储引擎？ <a class="header-anchor" href="#_1-1-为什么要了解存储引擎" aria-label="Permalink to &quot;1.1 为什么要了解存储引擎？&quot;">​</a></h2><p>从业务代码看，执行一条 <code>SELECT</code>/<code>UPDATE</code> 似乎非常简单，但在底层会涉及：</p><ul><li>如何在磁盘文件中定位到对应的数据页；</li><li>如何通过缓冲池（Buffer Pool）缓存热点数据；</li><li>如何在刷盘与性能之间做权衡。</li></ul><p>理解这些细节有助于你：</p><ul><li>设计更合理的主键与索引；</li><li>解释为什么某些 SQL 会导致大量随机 I/O；</li><li>在遇到 IOPS 瓶颈时与 DBA 更好地协同排查。</li></ul><h2 id="_1-2-innodb-存储结构的几个关键概念" tabindex="-1">1.2 InnoDB 存储结构的几个关键概念 <a class="header-anchor" href="#_1-2-innodb-存储结构的几个关键概念" aria-label="Permalink to &quot;1.2 InnoDB 存储结构的几个关键概念&quot;">​</a></h2><ul><li><strong>页（Page）</strong>：InnoDB 通常以 16KB 作为最小读写单位；</li><li><strong>索引组织表（Clustered Index）</strong>：数据按主键顺序存放在 B+ 树叶子节点中；</li><li><strong>二级索引（Secondary Index）</strong>：叶子节点存储主键值，需要回表；</li><li><strong>Buffer Pool</strong>：内存中的页缓存，决定了很多查询的真实延迟。</li></ul><p>在后续章节中，我们会结合示意图，深入分析这些结构之间的关系。</p>',10)])])}const g=n(r,[["render",t]]);export{u as __pageData,g as default};
